import React, { useRef, useEffect } from 'react';

const VideoAudioPlayer = ({ src, id, activeAudioId, onVisibilityChange }) => {
  const videoRef = useRef(null);
  const audioRef = useRef(null);
  const containerRef = useRef(null);
  const audioSrc = src.replace(/\.(mp4|webm)(\?.*)?$/i, '.mp3$2');

  useEffect(() => {
    const container = containerRef.current;
    if (!container) return;

    const observer = new IntersectionObserver(
      ([entry]) => {
        onVisibilityChange(id, entry.isIntersecting && entry.intersectionRatio > 0.5);
      },
      { threshold: 0.5 }
    );

    observer.observe(container);
    return () => observer.disconnect();
  }, [id, onVisibilityChange]);

  useEffect(() => {
    const audio = audioRef.current;
    if (!audio) return;
    if (activeAudioId === id) {
      audio.play().catch(() => {});
    } else {
      audio.pause();
    }
  }, [activeAudioId, id]);

  return (
    <div ref={containerRef} style={{ overflowAnchor: 'none' }}>
      <video
        ref={videoRef}
        src={src}
        autoPlay
        loop
        muted
        playsInline
        style={{ width: '100%', height: 'auto', display: 'block' }}
      />
      <audio
        ref={audioRef}
        src={audioSrc}
        loop
        style={{ position: 'absolute', left: '-9999px' }}
        tabIndex="-1"
      />
    </div>
  );
};

export default VideoAudioPlayer;
